use std::collections::VecDeque;

struct SensorDataStream {
    data: VecDeque<f64>,
    is_active: bool,
}

impl SensorDataStream {
    fn new() -> Self {
        SensorDataStream {
            data: VecDeque::new(),
            is_active: false,
        }
    }

    fn process(&mut self) -> Result<f64, String> {
        match (self.data.pop_front(), self.is_active) {
            (Some(val), true) => Ok(val),
            (None, true) => Err("Stream active but no data available".to_string()),
            (Some(_), false) => Err("Stream inactive, ignoring data".to_string()),
            (None, false) => Ok(f64::NAN),
        }
    }

    fn simulate_update(&mut self, value: Option<f64>, status: bool) {
        if let Some(v) = value { 
            self.data.push_back(v);
        }
        self.is_active = status;
    }
}

fn main() {
    let mut stream1 = SensorDataStream::new();
    stream1.simulate_update(Some(10.5), true);
    println!("Result 1: {:?}", stream1.process());

    let mut stream2 = SensorDataStream::new();
    stream2.simulate_update(None, true); 
    println!("Result 2: {:?}", stream2.process());

    let mut stream3 = SensorDataStream::new();
    stream3.simulate_update(Some(5.0), false);
    println!("Result 3: {:?}", stream3.process());

    let mut stream4 = SensorDataStream::new();
    stream4.simulate_update(None, false); 
    println!("Result 4: {:?}", stream4.process());
}

use std::fs;
use std::path::Path;
use serde::{Deserialize, Serialize};
use std::time::Duration;
use std::thread;
use std::io;

#[derive(Debug, Clone, Serialize, Deserialize)]
struct AppConfig {
    api_key: String,
    timeout_ms: u64,
    feature_flags: Vec<String>,
}

impl Default for AppConfig {
    fn default() -> Self {
        AppConfig {
            api_key: "default_key".to_string(),
            timeout_ms: 5000,
            feature_flags: vec!["logging".to_string()],
        }
    }
}

fn main() -> io::Result<()> {
    let config_path = Path::new("settings.json");
    let mut current_config = AppConfig::default();

    if !config_path.exists() {
        println!("Creating default settings file at {}", config_path.display());
        fs::write(config_path, &serde_json::to_string(&current_config).unwrap())?;
    }

    let mut last_modified = fs::metadata(config_path)?.modified()?;

    loop {
        thread::sleep(Duration::from_secs(2));

        match fs::metadata(config_path) {
            Ok(metadata) => {
                if metadata.modified()? > last_modified {
                    println!("n[Watcher] File modified detected. Reloading config...");
                    match fs::read_to_string(config_path) {
                        Ok(content) => match serde_json::from_str(&content) {
                            Ok(new_config) => {
                                current_config = new_config;
                                last_modified = metadata.modified()?;
                                println!("[SUCCESS] Configuration reloaded successfully!");
                                println!("New Timeout: {}ms", current_config.timeout_ms);
                            }
                            Err(e) => {
                                eprintln!("[ERROR] Failed to parse JSON content: {}", e);
                            }
                        },
                        Err(e) => {
                            eprintln!("[ERROR] Could not read file contents: {}", e);
                        }
                    }
                } else {
                    print!("r");
                }
            },
            Err(e) => {
                eprintln!("n[FATAL] Could not access config file: {}", e);
                break;
            }
        }
    }
    Ok(())
}

use std::fs::File;
use std::io::{self, Read, Seek};

struct ElfHeader {
    magic: u32,
    type_id: u32,
}

fn parse_elf_header(file_path: &str) -> io::Result<ElfHeader> {
    let mut file = File::open(file_path)?;
    let mut buffer = [0u8; 12];
    file.read_exact(&mut buffer)?; 

    let magic = u32::from_le_bytes([buffer[0], buffer[1], buffer[2], buffer[3]]);
    let type_id = u32::from_le_bytes([buffer[4], buffer[5], buffer[6], buffer[7]]);

    Ok(ElfHeader { magic, type_id }) 
}

fn main() -> io::Result<()> {
    let test_file = "test_binary.elf";
    if !std::path::Path::new(test_file).exists() {
        eprintln!("Please create a dummy ELF file named 'test_binary.elf' to run this example.");
        return Ok(()) 
    }

    match parse_elf_header(test_file) {
        Ok(header) => {
            if header.magic == 0x7f616c64 { // Basic magic check for ELF
                println!("Successfully parsed potential ELF file.");
                match header.type_id {
                    0 => println!("Type ID suggests executable code, proceeding with validation logic..."),
                    1 => println!("Type ID is a shared object, needs different handling."),
                    _ => println!("Unknown or unexpected file type based on magic/ID combination.")
                }
            } else {
                println!("File does not appear to have the standard ELF header signature.");
            }
        }
        Err(e) => {
            eprintln!("Error reading or parsing file: {}", e);
        }
    }
    Ok(())
}

use std::collections::HashMap;

struct SignatureResult {
    algorithm: String,
    data_payload: serde_json::Value
}

fn process_signature(result: &SignatureResult) -> Result<String, Box<dyn std::error::Error>> {
    match result.data_payload.as_object() {
        Some(obj) => {
            let alg = obj.get("algorithm");
            let status = obj.get("status");
            if let (Some(alg_val), Some(status_val)) = (alg, status) {
                println!("Matched structure for algorithm: {}", alg_val);
                return Ok(format!("Processed successfully for {}", status_val));
            }
            Err("Missing required keys in object".into())
        }
        None => match result.data_payload.get("raw_value") {
            Some(serde_json::Value::Number(num)) => {
                println!("Matched scalar numeric value");
                Ok(format!("Numeric result: {}", num.to_string()))
            }
            Some(serde_json::Value::Array(arr)) => {
                if arr.len() == 2 && result.algorithm == "coords" {
                    println!("Matched coordinate pair array");
                    let coords: Vec<f64> = arr.iter().map(|v| v.as_f64().unwrap()).collect();
                    Ok(format!("Coordinates found: ({:.2}, {:.2})", coords[0], coords[1]))
                }
                else {
                    println!("Matched generic array structure");
                    Ok(format!("Array of length {}", arr.len()))
                }
            }
            _ => Err("Unknown or unsupported data format received".into()),
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let results: Vec<SignatureResult> = vec![
        SignatureResult {
            algorithm: "jwt_rsa".to_string(),
            data_payload: serde_json::json!({"algorithm": "jwt_rsa", "status": "OK"}),
        },
        SignatureResult {
            algorithm: "coords".to_string(),
            data_payload: serde_json::json!([10.5, 22.1]),
        },
        SignatureResult {
            algorithm: "scalar".to_string(),
            data_payload: serde_json::json!({"raw_value": 3.14159}),
        },
        SignatureResult {
            algorithm: "generic".to_string(),
            data_payload: serde_json::json!([1, "two", true]),
        },
    ];

    for result in results {
        match process_signature(&result) {
            Ok(msg) => println!("Success processing {}: {}", result.algorithm, msg),
            Err(e) => eprintln!("Failure processing {}: {}", result.algorithm, e),
        }
    }

    Ok(())
}

use std::collections::HashMap;

struct JobResult {
    job_id: u32,
    status: String,
    output: Option<String>,
}

enum Message {
    Simple(String),
    JobUpdate(u32, String),
    Completed(JobResult),
}

fn process_message(msg: Message) -> Result<(), &'static str> {
    match msg {
        Message::Simple(s) => {
            println!("Received simple notification: {}", s);
            Ok(())
        }
        Message::JobUpdate(id, status) => {
            println!("Processing update for job {}: {}", id, status);
            if status == "FAILED" {
                Err("Job failed during processing")
            } else {
                Ok(()) 
            }
        }
        Message::Completed(result) => {
            println!("Successfully processed job {}", result.job_id);
            if let Some(output) = &result.output {
                println!("Final output captured: {}", output);
            } else {
                println!("No final output found for this job.");
            }
            Ok(()) 
        }
    }
}

fn main() {
    let msg1 = Message::Simple("System heartbeat received".to_string());
    let msg2 = Message::JobUpdate(101, "RUNNING".to_string());
    let msg3 = Message::Completed(JobResult { job_id: 101, status: "DONE".to_string(), output: Some("Final map-reduce result payload".to_string()) });
    let msg4 = Message::JobUpdate(205, "FAILED".to_string());

    process_message(msg1).ok();
    if let Err(e) = process_message(msg2) {
        println!("Error handling message 2: {}", e); 
    }
    process_message(msg3).ok();
    if let Err(e) = process_message(msg4) {
        println!("Error handling message 4: {}", e);
    }
}
